const text = $('Extract from File').item.json.text || '';
const sourceUrl = $input.first().json.source_url;
const model = $env.OPENROUTER_INGESTION_MODEL;

// Ambil max 15,000 karakter pertama untuk deteksi metadata
const headText = text.substring(0, 15000);

const systemPrompt = "Kamu adalah asisten hukum. Ekstrak metadata dari dokumen hukum ini.\n\nOutput WAJIB berupa JSON murni dengan struktur:\n{\n  \"metadata\": {\n    \"doc_type\": \"UU/PP/PMK/PER/dll\",\n    \"doc_number\": \"angka\",\n    \"doc_year\": \"4 digit\",\n    \"doc_title\": \"judul\",\n    \"jenis_pajak\": \"PPh/PPN/PBB/Umum/dll\",\n    \"status_hukum\": \"BERLAKU/DICABUT/DIUBAH\",\n    \"berlaku_sejak\": \"YYYY-MM-DD\",\n    \"dicabut_oleh\": \"\",\n    \"doc_category\": \"\"\n  }\n}";
const userPrompt = `Dokumen:\n${headText}`;

const payload = {
  model: model,
  temperature: 0.1,
  messages: [
    { role: 'system', content: systemPrompt },
    { role: 'user', content: userPrompt }
  ]
};

return [{
  json: {
    payload: payload,
    raw_full_text: text,
    source_url: sourceUrl
  }
}];

const raw = $json.choices[0].message.content;
const rawFullText = $('Prepare Metadata Request').item.json.raw_full_text;
const sourceUrl = $('Prepare Metadata Request').item.json.source_url;

let cleaned = raw.trim();
if (cleaned.startsWith('```json')) cleaned = cleaned.substring(7).trim();
else if (cleaned.startsWith('```')) cleaned = cleaned.substring(3).trim();
if (cleaned.endsWith('```')) cleaned = cleaned.substring(0, cleaned.length - 3).trim();

if (!cleaned.startsWith('{')) {
  const jsonStart = cleaned.indexOf('{');
  if (jsonStart !== -1) cleaned = cleaned.substring(jsonStart);
}
if (!cleaned.endsWith('}')) {
  const jsonEnd = cleaned.lastIndexOf('}');
  if (jsonEnd !== -1) cleaned = cleaned.substring(0, jsonEnd + 1);
}

let parsed = {};
try { 
  parsed = JSON.parse(cleaned); 
} catch(e) { 
  throw new Error('Metadata LLM gagal di-parse sebagai JSON. Raw Output:\n' + cleaned); 
}

const meta = parsed.metadata || parsed;

return [{
  json: {
    metadata: {
      doc_type: meta.doc_type || null,
      doc_number: meta.doc_number || null,
      doc_year: meta.doc_year || null,
      doc_title: meta.doc_title || null,
      jenis_pajak: meta.jenis_pajak || null,
      status_hukum: meta.status_hukum || 'BERLAKU',
      berlaku_sejak: meta.berlaku_sejak || null,
      dicabut_oleh: meta.dicabut_oleh || null,
      doc_category: meta.doc_category || null,
      source_url: sourceUrl
    },
    raw_full_text: rawFullText
  }
}];

const rawFullText = $input.first().json.raw_full_text;
const metadata = $input.first().json.metadata;
const model = $env.OPENROUTER_INGESTION_MODEL;

// Pecah menjadi blok 15.000 karakter agar LLM tidak kehabisan output token
const CHUNK_CHAR_SIZE = 15000;
const chunks = [];
for (let i = 0; i < rawFullText.length; i += CHUNK_CHAR_SIZE) {
  chunks.push(rawFullText.substring(i, i + CHUNK_CHAR_SIZE));
}

return chunks.map((chunkText, index) => {
  const systemPrompt = "Kamu adalah asisten hukum. Tugasmu hanya membersihkan teks OCR dokumen hukum ke Markdown yang rapi. HAPUS header, footer, nomor halaman, dan tanda tangan pejabat. PERTAHANKAN dan FORMAT struktur pasal. JANGAN tambahkan penjelasan apapun, JANGAN bungkus dengan JSON. HANYA Markdown murni.";
  const userPrompt = `Bersihkan teks bagian ini ke Markdown:\n\n${chunkText}`;

  return {
    json: {
      chunk_index: index,
      total_chunks: chunks.length,
      metadata: metadata,
      payload: {
        model: model,
        temperature: 0.1,
        messages: [
          { role: 'system', content: systemPrompt },
          { role: 'user', content: userPrompt }
        ]
      }
    }
  };
});

const items = $input.all();

// Urutkan kembali berdasarkan index agar teks nyambung sempurna
items.sort((a, b) => a.json.chunk_index - b.json.chunk_index);

let fullCleanedMarkdown = "";
for (const item of items) {
  let raw = item.json.choices[0].message.content.trim();
  if (raw.startsWith('```markdown')) raw = raw.substring(11).trim();
  else if (raw.startsWith('```')) raw = raw.substring(3).trim();
  if (raw.endsWith('```')) raw = raw.substring(0, raw.length - 3).trim();

  fullCleanedMarkdown += raw + "\n\n";
}

// Ambil metadata langsung dari node Parse Metadata karena HTTP Request menimpa item
const metadata = $('Parse Metadata').first().json.metadata;

return [{
  json: {
    cleanedMarkdown: fullCleanedMarkdown,
    ...metadata
  }
}];

const markdownText = $input.first().json.cleanedMarkdown;
const sourceUrl  = $input.first().json.source_url;
const docType    = $input.first().json.doc_type;
const docNumber  = $input.first().json.doc_number;
const docYear    = $input.first().json.doc_year;
const docTitle   = $input.first().json.doc_title;
const jenisPajak = $input.first().json.jenis_pajak;
const statusHukum = $input.first().json.status_hukum;
const berlakuSejak = $input.first().json.berlaku_sejak;
const dicabutOleh = $input.first().json.dicabut_oleh;
const docCategory = $input.first().json.doc_category;

const CHUNK_SIZE     = 1000;
const CHUNK_OVERLAP  = 150;
const MIN_CHUNK_SIZE = 100;

function splitByPasal(text) {
  const p = /(?=##\s+(?:Pasal|BAB|Bagian|Paragraf)\s+\d+)/gi;
  return text.split(p).filter(c => c.trim().length > MIN_CHUNK_SIZE);
}

function slidingWindow(text, size, overlap) {
  const chunks = [];
  let start = 0;
  while (start < text.length) {
    const end = Math.min(start + size, text.length);
    chunks.push(text.slice(start, end));
    start += size - overlap;
  }
  return chunks;
}

function extractPasalNumber(chunkText) {
  const match = chunkText.match(/##\s+Pasal\s+(\d+[A-Z]?)/i);
  return match ? match[1] : null;
}

const rawChunks = splitByPasal(markdownText);
const finalChunks = [];

for (const chunk of rawChunks) {
  if (chunk.length <= CHUNK_SIZE) {
    finalChunks.push(chunk);
  } else {
    const subChunks = slidingWindow(chunk, CHUNK_SIZE, CHUNK_OVERLAP);
    finalChunks.push(...subChunks);
  }
}

const output = finalChunks.map((chunk, index) => ({
  json: {
    chunk_text:   chunk.trim(),
    chunk_index:  index,
    total_chunks: finalChunks.length,
    pasal_number: extractPasalNumber(chunk),
    source_url:   sourceUrl,
    doc_type:     docType,
    doc_number:   docNumber,
    doc_year:     docYear,
    doc_title:    docTitle,
    jenis_pajak:  jenisPajak,
    status_hukum: statusHukum,
    berlaku_sejak: berlakuSejak,
    dicabut_oleh: dicabutOleh,
    doc_category: docCategory,
    ingested_at:  new Date().toISOString(),
  }
}));

return output;
